import Chat from "../models/Chat.js";
import Message from "../models/Message.js";
import User from "../models/User.js";
import mongoose from "mongoose";
import redis from "../../config/redis.js";
import { redisPub } from "../../config/redis.js";
import { emitToUser } from "../socket/socket.js";

const CHAT_MESSAGES_KEY = (chatId) => `chat:messages:${chatId}`;
const SERVER_ID = process.env.SERVER_ID || `server-${Math.random().toString(36).substring(7)}`;

const log = (tag, message, data = {}) => {
  console.log(`[${tag}] ${message}`, data);
};

const logError = (tag, error, extra = {}) => {
  console.error(`[${tag}] ERROR:`, {
    message: error.message,
    stack: error.stack,
    ...extra,
  });
};

// ===================== RATE LIMITING =====================
const checkMessageRateLimit = async (userId) => {
  try {
    const key = `rate:msg:${userId}`;
    const count = await redis.incr(key);

    if (count === 1) {
      await redis.expire(key, 1);
    }

    // Max 20 messages per second
    if (count > 20) {
      return false;
    }
    return true;
  } catch (err) {
    console.warn("[RATE_LIMIT] Redis failed, allowing message:", err.message);
    return true;
  }
};

// ===================== GET / CREATE CHAT =====================
export const getOrCreateChat = async (req, res) => {
  const userId = req.userId;
  const { friendId } = req.params;

  try {
    log("CHAT", "getOrCreateChat called", { userId, friendId });

    if (userId === friendId) {
      return res.status(400).json({ message: "Cannot chat with yourself" });
    }

    const isFriend = await User.exists({ _id: userId, friends: friendId });
    if (!isFriend) {
      log("CHAT", "Unauthorized chat attempt", { userId, friendId });
      return res.status(403).json({ message: "You can only chat with friends" });
    }

    const chat = await Chat.findOneAndUpdate(
      { participants: { $all: [userId, friendId], $size: 2 } },
      { $setOnInsert: { participants: [userId, friendId] } },
      { new: true, upsert: true }
    )
      .populate("participants", "fullName profilePic email")
      .populate("lastMessage")
      .lean();

    return res.status(200).json(chat);
  } catch (error) {
    logError("CHAT:getOrCreateChat", error, { userId, friendId });
    return res.status(500).json({ message: "Internal server error" });
  }
};

// ===================== GET USER CHATS =====================
export const getUserChats = async (req, res) => {
  const userId = req.userId;

  try {
    log("CHAT", "getUserChats", { userId });

    const chats = await Chat.find({ participants: userId })
      .populate("participants", "fullName profilePic")
      .populate("lastMessage", "content sender createdAt status")
      .sort({ updatedAt: -1 })
      .limit(50)
      .lean();

    return res.status(200).json(chats);
  } catch (error) {
    logError("CHAT:getUserChats", error, { userId });
    return res.status(500).json({ message: "Internal server error" });
  }
};
// ===================== SEND MESSAGE =====================
export const sendMessage = async (req, res) => {
  const userId = req.userId;
  const { chatId } = req.params;
  const { text } = req.body;

  try {
    log("MESSAGE", "sendMessage request", { userId, chatId, textLength: text?.length });

    if (!text || !text.trim()) {
      return res.status(400).json({ message: "Message cannot be empty" });
    }

    // ⚡ Rate limiting
    const isAllowed = await checkMessageRateLimit(userId);
    if (!isAllowed) {
      return res.status(429).json({ message: "Too many messages. Please slow down." });
    }

    const chat = await Chat.findById(chatId).lean();
    if (!chat) {
      return res.status(404).json({ message: "Chat not found" });
    }

    if (!chat.participants.some(id => id.toString() === userId.toString())) {
      log("MESSAGE", "Unauthorized send attempt", { userId, chatId });
      return res.status(403).json({ message: "Not authorized" });
    }

    const receiverId = chat.participants.find(
      id => id.toString() !== userId.toString()
    );

    if (!receiverId || receiverId.toString() === userId.toString()) {
      return res.status(400).json({ message: "Invalid receiver" });
    }

    const receiverOnline = await redis.sismember("online_users", receiverId.toString());
    const initialStatus = receiverOnline ? "delivered" : "sent";

    // 🚀 Create message (NO transaction → faster)
    const message = await Message.create({
      chatId,
      sender: userId,
      content: text.trim(),
      status: initialStatus,
    });

    log("MESSAGE", "Message created in DB", { messageId: message._id, content: message.content, status: initialStatus });

    // Update last message in chat
    const updatedChat = await Chat.findByIdAndUpdate(
      chatId,
      {
        lastMessage: message._id,
        updatedAt: new Date(),
      },
      { new: true }
    ).lean();

    // 🔄 Serialize
    const msg = message.toObject();
    const serializedMessage = {
      ...msg,
      _id: msg._id.toString(),
      chatId: msg.chatId.toString(),
      sender: {
        _id: userId,
        fullName: req.user?.fullName, // Assuming protect middleware adds user to req
        profilePic: req.user?.profilePic
      },
      createdAt: msg.createdAt.toISOString(),
      updatedAt: msg.updatedAt.toISOString(),
    };

    // ⚡ CACHE INVALIDATION: Instead of just pushing, let's clear to ensure consistency
    // or we could append, but clearing is safer if we want to guarantee the view is correct.
    // However, rpush is faster. Let's stick with rpush but ensure we handle deletions correctly.
    try {
      const key = CHAT_MESSAGES_KEY(chatId);
      // If we don't clear, deleted messages stay in cache until it expires.
      // So we MUST invalidate cache on deletion.
      await redis.rpush(key, JSON.stringify(serializedMessage));
      await redis.ltrim(key, -100, -1);
      await redis.expire(key, 300);
    } catch (err) {
      console.warn("[CACHE] Append failed:", err.message);
    }

    // 📡 Publish (real-time delivery)
    try {
      await redisPub.publish(
        "message:new",
        JSON.stringify({
          receiverId: receiverId.toString(),
          message: serializedMessage,
          _origin: SERVER_ID,
          delivered: receiverOnline,
        })
      );

      if (receiverOnline) {
        emitToUser(userId.toString(), "message-status-update", {
          messageId: message._id.toString(),
          status: "delivered",
        });

        await redisPub.publish(
          "message:status",
          JSON.stringify({
            senderId: userId.toString(),
            messageId: message._id.toString(),
            status: "delivered",
            _origin: SERVER_ID,
          })
        );
      }
    } catch (err) {
      console.error("[REDIS_PUBLISH_ERROR]", err.message);
    }

    log("MESSAGE", "Message sent successfully", {
      messageId: message._id,
      chatId,
      sender: userId,
      receiver: receiverId,
    });

    return res.status(201).json(serializedMessage);

  } catch (error) {
    logError("MESSAGE:sendMessage", error, { userId, chatId });
    return res.status(500).json({ message: "Internal server error" });
  }
};

// ===================== DELETE MESSAGES (BULK) =====================
export const deleteMessages = async (req, res) => {
  const userId = req.userId;
  const { chatId } = req.params;
  const { messageIds } = req.body;

  try {
    log("MESSAGE", "deleteMessages (HARD DELETE) request", { userId, chatId, count: messageIds?.length });

    if (!Array.isArray(messageIds) || messageIds.length === 0) {
      return res.status(400).json({ message: "Invalid message IDs" });
    }

    const chat = await Chat.findById(chatId).lean();
    if (!chat) {
      log("MESSAGE", "Chat not found for deletion", { chatId });
      return res.status(404).json({ message: "Chat not found" });
    }

    if (!chat.participants.some(id => id.toString() === userId.toString())) {
      log("MESSAGE", "Unauthorized deletion attempt", { userId, chatId });
      return res.status(403).json({ message: "Not authorized" });
    }

    // ⚡ HARD DELETE from MongoDB (remove document entirely)
    // Only delete messages owned by the user in this specific chat
    const result = await Message.deleteMany({
      _id: { $in: messageIds },
      chatId: chatId,
      sender: userId
    });

    log("MESSAGE", "Messages deleted from MongoDB", { deletedCount: result.deletedCount });

    // ⚡ SYNC CHAT lastMessage: If the last message was deleted, update it
    if (chat.lastMessage && messageIds.includes(chat.lastMessage.toString())) {
      const lastMsg = await Message.findOne({ chatId })
        .sort({ createdAt: -1 })
        .select("_id")
        .lean();
      
      await Chat.findByIdAndUpdate(chatId, {
        lastMessage: lastMsg ? lastMsg._id : null
      });
      log("MESSAGE", "Chat lastMessage updated after deletion", { chatId, newLastMessage: lastMsg?._id });
    }

    // ⚡ INVALIDATE REDIS CACHE (MANDATORY)
    try {
      const cacheKey = CHAT_MESSAGES_KEY(chatId);
      const deletedFromCache = await redis.del(cacheKey);
      log("CACHE", "Invalidated chat messages cache", { chatId, cacheKey, deletedFromCache });
    } catch (err) {
      logError("CACHE:Invalidation", err, { chatId });
    }

    // 📡 Publish deletion event to all participants
    try {
      await redisPub.publish(
        "messages:deleted",
        JSON.stringify({
          chatId: chatId.toString(),
          messageIds: messageIds,
          senderId: userId.toString(),
          participants: chat.participants.map(p => p.toString()),
          _origin: SERVER_ID,
        })
      );
      log("MESSAGE", "Published deletion event to Redis", { chatId, messageCount: messageIds.length });
    } catch (err) {
      logError("REDIS_PUBLISH", err, { chatId });
    }

    return res.status(200).json({
      message: "Messages deleted permanently",
      deletedCount: result.deletedCount
    });

  } catch (error) {
    logError("MESSAGE:deleteMessages", error, { userId, chatId });
    return res.status(500).json({ message: "Internal server error" });
  }
};

// ===================== GET CHAT MESSAGES =====================
export const getChatMessages = async (req, res) => {
  const userId = req.userId;
  const { chatId } = req.params;
  const { limit = 50, before } = req.query;

  const parsedLimit = Math.min(parseInt(limit) || 50, 1000);

  try {
    log("MESSAGE", "getChatMessages", { userId, chatId, before });

    const chat = await Chat.findById(chatId).lean();
    if (!chat) {
      return res.status(404).json({ message: "Chat not found" });
    }

    if (!chat.participants.some(id => id.toString() === userId.toString())) {
      return res.status(403).json({ message: "Not authorized" });
    }

    const query = {
      chatId: new mongoose.Types.ObjectId(chatId),
    };

    log("MESSAGE", "Query constructed", { chatId, query: JSON.stringify(query) });

    if (before) {
      const date = new Date(before);
      if (!isNaN(date.getTime())) {
        query.createdAt = { $lt: date };
        log("MESSAGE", "Added before filter", { before, date });
      }
    }

    // 🔥 CACHE (only for initial load)
    if (!before) {
      try {
        const key = CHAT_MESSAGES_KEY(chatId);
        const cached = await redis.lrange(key, -parsedLimit, -1);

        if (cached?.length) {
          const messages = cached
            .map(m => {
              try {
                return JSON.parse(m);
              } catch {
                return null;
              }
            })
            .filter(Boolean);

          log("CACHE", "hit", { chatId, count: messages.length });

          return res.status(200).json({
            messages,
            pagination: {
              hasMore: true, // Always allow loading older messages from DB if we hit cache
              lastTimestamp: messages[0]?.createdAt || null,
              limit: parsedLimit,
            },
          });
        }
      } catch (err) {
        console.warn("[CACHE] read failed:", err.message);
      }
    }

    // 🗄️ DB FALLBACK
    const messages = await Message.find(query)
      .populate("sender", "fullName profilePic")
      .sort({ createdAt: -1 }) // newest first
      .limit(parsedLimit)
      .lean();

    log("MESSAGE", "Loaded messages from DB", { 
      count: messages.length, 
      chatId,
      query: JSON.stringify(query),
    });

    const orderedMessages = messages.reverse(); // oldest → newest

    // 🔥 CACHE WRITE (only initial load)
    if (!before && orderedMessages.length) {
      try {
        const key = CHAT_MESSAGES_KEY(chatId);
        
        // Use a pipeline to clear and rebuild cache atomically
        const pipeline = redis.multi();
        pipeline.del(key);

        for (const msg of orderedMessages) {
          const serialized = {
            ...msg,
            _id: msg._id.toString(),
            chatId: msg.chatId.toString(),
            sender: msg.sender ? {
              ...msg.sender,
              _id: msg.sender._id.toString(),
            } : null,
            createdAt: msg.createdAt instanceof Date ? msg.createdAt.toISOString() : msg.createdAt,
            updatedAt: msg.updatedAt instanceof Date ? msg.updatedAt.toISOString() : msg.updatedAt,
          };
          pipeline.rpush(key, JSON.stringify(serialized));
        }
        
        pipeline.expire(key, 300);
        await pipeline.exec();
        
        log("CACHE", "Cache rebuilt for chat", { chatId, count: orderedMessages.length });
      } catch (err) {
        console.warn("[CACHE] Cache rebuild failed:", err.message);
      }
    }

    return res.status(200).json({
      messages: orderedMessages,
      pagination: {
        hasMore: orderedMessages.length === parsedLimit,
        lastTimestamp: orderedMessages[0]?.createdAt || null,
        limit: parsedLimit,
      },
    });

  } catch (error) {
    logError("MESSAGE:getChatMessages", error, { userId, chatId });
    return res.status(500).json({ message: "Internal server error" });
  }
};

// ===================== GET SINGLE MESSAGE =====================
export const getMessage = async (req, res) => {
  const userId = req.userId;
  const { messageId } = req.params;

  try {
    log("MESSAGE", "getMessage", { messageId });

    const message = await Message.findById(messageId)
      .populate("sender", "fullName profilePic")
      .lean();

    if (!message) {
      return res.status(404).json({ message: "Message not found" });
    }

    // 🔥 SECURITY CHECK
    const chat = await Chat.findById(message.chatId).lean();

    if (!chat || !chat.participants.some(id => id.toString() === userId.toString())) {
      return res.status(403).json({ message: "Not authorized" });
    }

    return res.status(200).json(message);

  } catch (error) {
    logError("MESSAGE:getMessage", error, { messageId });
    return res.status(500).json({ message: "Internal server error" });
  }
};
